export function IcoMapSatelliteTile() {
  const { palette } = useIlloStyle();
  return (
    <svg viewBox="0 0 200 130" preserveAspectRatio="xMidYMid slice" style={{ width: '100%', height: '100%' }}>
      <rect width="200" height="130" fill={palette.dark} />
      {/* Satellite dish oval */}
      <ellipse cx="90" cy="78" rx="42" ry="28" fill="none" stroke={palette.accent} strokeWidth="3" transform="rotate(-30,90,78)" />
      {/* Dish inner */}
      <ellipse cx="90" cy="78" rx="30" ry="20" fill={palette.mid} opacity="0.3" transform="rotate(-30,90,78)" />
      {/* Pole */}
      <line x1="90" y1="90" x2="90" y2="112" stroke={palette.mid} strokeWidth="4" strokeLinecap="round" />
      <line x1="75" y1="112" x2="105" y2="112" stroke={palette.mid} strokeWidth="3.5" strokeLinecap="round" />
      {/* Dish focal point / arm */}
      <line x1="90" y1="78" x2="118" y2="52" stroke={palette.accent} strokeWidth="2.5" strokeLinecap="round" />
      <circle cx="120" cy="50" r="4" fill={palette.accent} />
      {/* Beam lines pointing up-right */}
      <line x1="122" y1="46" x2="145" y2="28" stroke={palette.accent} strokeWidth="2" strokeDasharray="4 3" opacity="0.8" />
      <line x1="126" y1="50" x2="152" y2="35" stroke={palette.accent} strokeWidth="2" strokeDasharray="4 3" opacity="0.6" />
      <line x1="118" y1="44" x2="140" y2="22" stroke={palette.accent} strokeWidth="2" strokeDasharray="4 3" opacity="0.4" />
    </svg>
  );
}
